_REVIEW_JS = r"""
var RT={'strong-green':'#22C55E','green':'#22C55E','blue':'#38BDF8','amber':'#FFB23F','red':'#EF4444','gray':'#8794ab'};
var RFILTER='all',RDATA=null;
var RGROUP={all:function(){return true;},
  buy:function(b){return b.decision==='STRONG_BUY'||b.decision==='BUY'||b.decision==='BUY_PULLBACK';},
  watch:function(b){return b.decision==='WATCH_BREAKOUT'||b.decision==='WAIT'||b.decision==='TOO_LATE';},
  avoid:function(b){return b.decision==='AVOID'||b.decision==='NO_NEW_RISK';},
  contra:function(b){return b.has_contradiction;},
  hiconf:function(b){return b.confidence>=65;}};
function rReviewRow(b){var tc=RT[b.tone]||'#8794ab';
  return '<div onclick="location.href=\'/titre/'+b.symbol+'\'" style="cursor:pointer;display:grid;grid-template-columns:70px 128px 62px 1fr 30px;gap:10px;align-items:center;padding:10px 12px;border-top:1px solid #ffffff0a">'
    +'<b style="font-size:13px">'+b.symbol+'</b>'
    +'<span style="font-size:10px;font-weight:800;color:'+tc+';background:'+tc+'18;border:1px solid '+tc+'44;border-radius:8px;padding:2px 6px;text-align:center">'+b.label+'</span>'
    +'<span style="display:flex;align-items:center;gap:6px"><span style="width:6px;height:6px;border-radius:50%;background:'+tc+'"></span><b style="color:'+tc+';font-size:12px">'+b.confidence+'</b></span>'
    +'<span style="font-size:11px;color:#8794AB;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+(b.view||'')+(b.has_contradiction?' <span style="color:#FFB23F">· ⚠ '+(b.devils_advocate||'contradiction')+'</span>':(b.top_con?' · '+b.top_con:''))+'</span>'
    +'<span style="color:#6B7280;font-size:12px;text-align:right">›</span></div>';}
function rPill(id,lab,n){var on=RFILTER===id;return '<button type="button" onclick="rSetF(\''+id+'\')" style="font-size:11px;font-weight:800;padding:4px 12px;border-radius:8px;cursor:pointer;border:1px solid '+(on?'#FF7A18':'rgba(255,255,255,.14)')+';background:'+(on?'rgba(255,122,24,.16)':'#0e0e12')+';color:'+(on?'#FF7A18':'#8794AB')+'">'+lab+(n!=null?' '+n:'')+'</button>';}
window.rSetF=function(f){RFILTER=f;rRender();};
function rRender(){if(!RDATA)return;var revs=RDATA.reviews||[];
  var n=function(fn){return revs.filter(fn).length;};
  document.getElementById('rPills').innerHTML=rPill('all','Tous',revs.length)+rPill('buy','🟢 Achat',n(RGROUP.buy))+rPill('watch','🟡 Surveiller',n(RGROUP.watch))+rPill('avoid','🔴 Éviter',n(RGROUP.avoid))+rPill('contra','⚠ Contradictions',n(RGROUP.contra))+rPill('hiconf','💪 Confiance ≥65',n(RGROUP.hiconf));
  var list=revs.filter(RGROUP[RFILTER]||RGROUP.all);
  document.getElementById('rList').innerHTML=list.length?'<div style="display:grid;grid-template-columns:70px 128px 62px 1fr 30px;gap:10px;padding:0 12px 4px;font-size:9px;color:#6b7280;font-weight:800;letter-spacing:.4px;text-transform:uppercase"><span>Titre</span><span>Décision</span><span>Conf.</span><span>Vue du comité / tension</span><span></span></div>'+list.map(rReviewRow).join(''):'<div class="muted" style="padding:20px;text-align:center">Aucun titre dans ce filtre.</div>';
}
function loadReview(){fetch('/api/committee-review').then(function(r){return r.json();}).then(function(d){RDATA=d;
  var cap=d.count>=d.capped_at?' · <span style="color:#FFB23F">affichage borné à '+d.capped_at+'</span>':'';
  document.getElementById('rHead').innerHTML=(d.data_source==='demo'?'🎭 démo · ':'')+d.count+' titres passés en revue par le comité'+cap+' · '+(d.as_of?'scan '+d.as_of:'');
  rRender();}).catch(function(){document.getElementById('rList').innerHTML='<div class="muted" style="padding:20px">Revue indisponible.</div>';});}
loadReview();setInterval(loadReview,120000);
"""

PAGE_REVIEW = _vpage('Committee Review',
  '<div class="vhead"><div><h1>🏛️ Committee Review</h1><div class="s" id="rHead">le comité passe l\'univers en revue…</div></div></div>'
  '<div id="rPills" style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px"></div>'
  '<div class="vcard" style="padding:6px 4px"><div id="rList"></div></div>'
  '<div class="muted" style="text-align:center;font-size:11px;margin:20px 0">⛔ analyse éducative · aucune certitude · aucun ordre · le comité éclaire, il ne décide pas à ta place · les contradictions sont affichées, jamais masquées</div>',
  js=_REVIEW_JS)


