_DECJ_JS = r"""
var DJT={'strong-green':'#22C55E','green':'#22C55E','blue':'#38BDF8','amber':'#FFB23F','red':'#EF4444','gray':'#8794ab'};
function djLoad(){try{return JSON.parse(localStorage.getItem('vxDecisions')||'[]');}catch(e){return[];}}
function djSave(l){try{localStorage.setItem('vxDecisions',JSON.stringify(l));}catch(e){}}
function djAgo(ts){var d=(Date.now()-new Date(ts).getTime())/86400000;if(d<1)return "aujourd'hui";if(d<2)return 'hier';return Math.floor(d)+' j';}
window.djOutcome=function(id,v){var l=djLoad();for(var i=0;i<l.length;i++){if(l[i].id===id){l[i].outcome=l[i].outcome===v?null:v;}}djSave(l);djRender();};
window.djDel=function(id){var l=djLoad().filter(function(x){return x.id!==id;});djSave(l);djRender();};
window.djClear=function(){if(confirm('Effacer tout le journal des décisions de cet appareil ?')){djSave([]);djRender();}}
function djCard(d){var tc=DJT[d.tone]||'#8794ab';
  var oc=d.outcome==='held'?'#22C55E':d.outcome==='invalidated'?'#EF4444':null;
  var ob=function(v,lab,col){var on=d.outcome===v;return '<button type="button" onclick="djOutcome('+d.id+',\''+v+'\')" style="font-size:10px;font-weight:800;cursor:pointer;border-radius:8px;padding:4px 8px;border:1px solid '+(on?col:'rgba(255,255,255,.14)')+';background:'+(on?col+'22':'transparent')+';color:'+(on?col:'#8794ab')+'">'+lab+'</button>';};
  return '<div class="vcard" style="padding:14px 16px;border-left:3px solid '+tc+'">'
    +'<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap">'
      +'<b onclick="location.href=\'/titre/'+d.symbol+'\'" style="font-size:15px;cursor:pointer">'+d.symbol+'</b>'
      +'<span style="font-size:11px;font-weight:900;color:'+tc+';background:'+tc+'1a;border:1px solid '+tc+'55;padding:2px 10px;border-radius:8px">'+(d.label||d.decision)+'</span>'
      +(oc?'<span style="font-size:10px;font-weight:800;color:'+oc+'">'+(d.outcome==='held'?'✓ thèse tenue':'✗ thèse invalidée')+'</span>':'')
      +'<span style="margin-left:auto;font-size:11px;color:#6B7280">'+djAgo(d.ts)+' · conf. '+d.confidence+'/100</span></div>'
    +'<div style="font-size:12px;color:#8794AB;margin-top:6px">Comité : <b style="color:#C9D2E0">'+(d.view||'—')+'</b> · accord '+(d.agreement!=null?d.agreement+'%':'—')+(d.price!=null?' · figée à $'+d.price:'')+(d.has_contradiction?' · <span style="color:#FFB23F">⚠ contradiction</span>':'')+'</div>'
    +(d.top_pro?'<div style="font-size:12px;color:#C9D2E0;margin-top:4px"><span class="up">✓</span> '+d.top_pro+'</div>':'')
    +(d.devils_advocate?'<div style="font-size:12px;color:#C9D2E0;margin-top:2px"><span class="dn">😈</span> '+d.devils_advocate+'</div>':'')
    +(d.invalidation!=null?'<div style="font-size:11px;color:#8794ab;margin-top:4px">⛔ Invalidée si sous $'+d.invalidation+'</div>':'')
    +'<div style="display:flex;gap:6px;margin-top:10px;align-items:center"><span style="font-size:9px;color:#6b7280;font-weight:800;letter-spacing:.4px;text-transform:uppercase">Verdict a posteriori :</span>'
      +ob('held','✓ Tenue','#22C55E')+ob('invalidated','✗ Invalidée','#EF4444')
      +'<button type="button" onclick="djDel('+d.id+')" style="margin-left:auto;font-size:10px;color:#6B7280;background:transparent;border:1px solid rgba(255,255,255,.12);border-radius:8px;padding:4px 8px;cursor:pointer">Retirer</button></div></div>';}
function djRender(){if(!document.getElementById('djStats')||!document.getElementById('djList'))return;var l=djLoad();
  var held=l.filter(function(x){return x.outcome==='held';}).length,inv=l.filter(function(x){return x.outcome==='invalidated';}).length,rated=held+inv;
  document.getElementById('djStats').innerHTML=l.length?'<div class="kpi"><div class="kl">Décisions épinglées</div><div class="kv">'+l.length+'</div></div>'
    +'<div class="kpi"><div class="kl">✓ Thèses tenues</div><div class="kv" style="color:#22C55E">'+held+'</div></div>'
    +'<div class="kpi"><div class="kl">✗ Invalidées</div><div class="kv" style="color:#EF4444">'+inv+'</div></div>'
    +'<div class="kpi"><div class="kl">Taux de tenue</div><div class="kv">'+(rated?Math.round(held/rated*100)+'%':'—')+'</div></div>':'';
  document.getElementById('djList').innerHTML=l.length?l.map(djCard).join(''):'<div class="vcard" style="text-align:center;padding:32px;color:#8794ab">Aucune décision épinglée pour l\'instant.<br><span style="font-size:12px">Ouvre une fiche, puis « 📌 Épingler au journal » dans la Salle du Comité pour figer le verdict et le revoir plus tard.</span></div>';
}
djRender();
"""

PAGE_DECISIONS = _vpage('Journal des décisions',
  '<div class="vhead"><div><h1>📝 Journal des décisions</h1><div class="s">Fige le verdict du comité, reviens dessus, apprends · <b style="color:#F5B45B">discipline de revue</b> · 🔒 privé, sur cet appareil uniquement</div></div>'
  '<div style="margin-left:auto;align-self:center"><button class="vbtn dng" onclick="djClear()">Tout effacer</button></div></div>'
  '<div class="kpiband" id="djStats" style="grid-template-columns:repeat(auto-fit,minmax(150px,1fr));margin-bottom:8px"></div>'
  '<div id="djList" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:12px"></div>'
  '<div class="muted" style="text-align:center;font-size:11px;margin:20px 0">⛔ analyse éducative · aucun ordre · le « verdict a posteriori » sert à apprendre, pas à noter une performance · données locales, jamais envoyées au serveur</div>',
  js=_DECJ_JS)


