  # ───────────── REFONTE DESK · système de design (dk2-*) — sobre, institutionnel ─────────────
  ".dk2{--ok:#22C55E;--no:#EF4444;--at:#FF7A18;--in:#38BDF8;--wn:#F5B45B;--mut:#8794ab;--ln:rgba(255,255,255,.07);--card:#121316;--card2:#0e0f12}"
